#include "firebase_rtdb.h"
#include <WiFi.h>
#include <Firebase_ESP_Client.h>
static FirebaseData fbdo;
static FirebaseAuth auth;
static FirebaseConfig config;
void firebase_setup(const char*host,const char*key){config.database_url=host;config.api_key=key;Firebase.begin(&config,&auth);Firebase.reconnectWiFi(true);Serial.println("[firebase] OK");}
void firebase_loop(){}
bool firebase_set_float(const char*p,float v){return Firebase.RTDB.setFloat(&fbdo,p,v);}
bool firebase_set_string(const char*p,const char*v){return Firebase.RTDB.setString(&fbdo,p,v);}
float firebase_get_float(const char*p){Firebase.RTDB.getFloat(&fbdo,p);return fbdo.floatData();}
String firebase_get_string(const char*p){Firebase.RTDB.getString(&fbdo,p);return fbdo.stringData();}
